 1	import React, { FC, ReactNode } from 'react';
 2	
 3	import NewBadge from '@kubevirt-utils/components/badges/NewBadge/NewBadge';
 4	import HelpTextIcon from '@kubevirt-utils/components/HelpTextIcon/HelpTextIcon';
 5	import { PopoverPosition, Split, SplitItem, Switch } from '@patternfly/react-core';
 6	
 7	import ExpandSection from '../../../views/clusteroverview/SettingsTab/ExpandSection/ExpandSection';
 8	
 9	import './ExpandSectionWithSwitch.scss';
10	
11	type ExpandSectionWithSwitchProps = {
12	  children: ReactNode;
13	  helpTextIconContent?: ReactNode;
14	  id?: string;
15	  isDisabled?: boolean;
16	  newBadge: boolean;
17	  switchIsOn: boolean;
18	  toggleContent?: ReactNode;
19	  toggleText?: string;
20	  turnOnSwitch: (checked: boolean) => void;
21	};
22	
23	const ExpandSectionWithSwitch: FC<ExpandSectionWithSwitchProps> = ({
24	  children,
25	  helpTextIconContent,
26	  id,
27	  isDisabled,
28	  newBadge = false,
29	  switchIsOn,
30	  toggleContent,
31	  toggleText,
32	  turnOnSwitch,
33	}) => (
34	  <Split className="expand-section-with-switch" id={id}>
35	    <SplitItem>
36	      <ExpandSection isDisabled={isDisabled} toggleContent={toggleContent} toggleText={toggleText}>
37	        {children}
38	      </ExpandSection>
39	    </SplitItem>
40	    {helpTextIconContent && (
41	      <SplitItem isFilled>
42	        <HelpTextIcon
43	          bodyContent={helpTextIconContent}
44	          helpIconClassName="expand-section-with-switch__help-icon"
45	          position={PopoverPosition.right}
46	        />
47	        {newBadge && <NewBadge />}
48	      </SplitItem>
49	    )}
50	    <SplitItem>
51	      <Switch
52	        isChecked={switchIsOn}
53	        isDisabled={isDisabled}
54	        onChange={(_, checked: boolean) => turnOnSwitch(checked)}
55	      />
56	    </SplitItem>
57	  </Split>
58	);
59	
60	export default ExpandSectionWithSwitch;

